head.script:
// 사용자 ID, 사용자명 불러오는 코드
scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;
scwin.userNm = scwin.memJson.userNm;


const MSG_LO_ERR_001 = "현재비밀번호를 입력하세요.";
const MSG_LO_ERR_002 = "새비밀번호를 입력하세요.";
const MSG_LO_ERR_003 = "새비밀번호확인을 입력하세요.";
const MSG_LO_ERR_004 = "현재비밀번호와 새비밀번호 값이 같습니다. 다른값을 입력하세요.";
const MSG_LO_ERR_005 = "새비밀번호와 새비밀번호확인 값이 다릅니다. 같은값을 입력하세요.";
const MSG_LO_ERR_006 = "입력하신 비밀번호가 다릅니다. 정확히 입력하세요.";
const MSG_LO_ERR_011 = "사용자ID를 입력하세요.";
const MSG_LO_ERR_012 = "사용자명을 입력하세요.";
const MSG_LO_ERR_013 = "휴대폰번호를 입력하세요.";
const MSG_LO_ERR_014 = "인증번호 전송을 진행하세요.";
const MSG_LO_ERR_015 = "인증번호를 입력하세요.";
const MSG_LO_ERR_016 = "휴대폰전화번호를 정확하게 입력해 주십시오.";

scwin.vAuthNoYn = "N";
scwin.toDay = WebSquare.date.getCurrentServerDate();
scwin.day = WebSquare.date.dateAdd(WebSquare.date.getCurrentServerDate(), 1);


scwin.onpageload = function () {
    // disable 처리

    // to-do 확인 필요..
    scwin.now = new Date();
    scwin.minute = scwin.now.getMinutes().toString();
    scwin.second = scwin.now.getSeconds().toString();
    scwin.minute = 5; // test중
    scwin.second = 00;
    scwin.end = 0;

    $c.gus.cfDisableKeyData();
    txt_userId.setValue(scwin.userId);
    txt_userNm.setValue(scwin.userNm);
    $c.gus.cfDisableKeyData([]);
    txt_userId.setDisabled(true);
    txt_userNm.setDisabled(true);
};


//-------------------------------------------------------------------------
// 저장 : 
//-------------------------------------------------------------------------
scwin.f_Update = async function () {
    let ret = await scwin.f_ReqFieldChk()
    if (ret) {
        $c.sbm.execute(sbm_saveEmp);
    }
}


//-------------------------------------------------------------------------
//  필수입력항목 체크 
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = function () {
    //필수입력항목 체크
    var passwd = "null";
    // var oldPasswd = document.all.txt_oldPasswd.value.trim();
    // var newPasswd = document.all.txt_newPasswd.value.trim();         
    // var confirmPasswd = document.all.txt_confirmPasswd.value.trim(); 
    var newPasswd = txt_newPasswd.getValue();         // to-do
    var confirmPasswd = txt_confirmPasswd.getValue(); // to-do

    if (newPasswd == "") {
        $c.win.alert(MSG_LO_ERR_002);
        return false;
    }

    if (confirmPasswd == "") {
        $c.win.alert(MSG_LO_ERR_003);
        return false;
    }

    if (newPasswd != confirmPasswd) {
        $c.win.alert(MSG_LO_ERR_005);
        return false;
    }

    if (!scwin.f_passwordCheck(txt_userId.getValue(), newPasswd)) {
        txt_newPasswd.focus();
        return false;
    }

    if (passwd == newPasswd) {
        $c.win.alert(MSG_LO_ERR_004);
        return false;
    }
    return true;
}


scwin.f_passwordCheck = function (vUserId, vPassword) {
    var iLen = vPassword.length;
    var engCnt = $c.gus.cfisEnglishCnt(vPassword);
    var numCnt = $c.gus.cfisNumberCnt(vPassword);

    if ($c.gus.cfnumChainChk(vPassword)) {
        $c.win.alert("비밀번호는 연속 또는 동일한  숫자 3자리 이상  사용할 수 없습니다.");
        return false;
    }

    if (iLen < 10) {
        $c.win.alert("비밀번호는 10자리 이상이어야 합니다.");
        return false;
    }

    if (!scwin.f_specialPatternCheck(vPassword)) {
        $c.win.alert("비밀번호는 특수문자가 포함되어야 합니다.");
        return false;
    }

    if (engCnt == 0 || numCnt == 0) {
        $c.win.alert("비밀번호는 영어+숫자+특수문자 조합이어야 합니다.");
        return false;
    }

    if (vUserId == vPassword) {
        $c.win.alert("사용자ID를 비밀번호로 사용할  수  없습니다.");
        return false;
    }
    return true;
}


//특수문자 입력체크
scwin.f_specialPatternCheck = function (vPassword) {
    var special_pattern = /[`~!@#$%^&*|\\\'\";:\/?]/gi;

    if (special_pattern.test(vPassword) == true) {
        return true;
    } else {
        return false;
    }
}


scwin.jsLogin = function () {

    oGDS_login.insertRow();
    oGDS_login.setCellData(0, "userId", txt_userId.getValue());
    oGDS_login.setCellData(0, "passwd", txt_newPasswd.getValue());
    oGDS_login.setCellData(0, "passwdCheckCnt", 1);

    sbm_login.action = "/login.do"; // 확인필요...

    $c.sbm.execute(sbm_login);

    window.close();
}

//2022 2차인증 추가

//필수입력항목 체크
scwin.f_AuthReqFieldChk = async function () {
    if (txt_userId.getValue() == "") {
        await $c.win.alert(MSG_LO_ERR_011);
        return false;
    }
    if (txt_userNm.getValue() == "") {
        await $c.win.alert(MSG_LO_ERR_012);
        return false;
    }
    if (txt_oldPasswd.getValue() == "") {
        await $c.win.alert(MSG_LO_ERR_001);
        return false;
    }
    if (txt_userMpNo.getValue() == "") {
        await $c.win.alert(MSG_LO_ERR_013);
        return false;
    } else {
        var vTelNo = txt_userMpNo.getValue();
        var regExp = /^(01[016789]{1}|02|0[3-9]{1}[0-9]{1})-?[0-9]{3,4}-?[0-9]{4}$/;

        if (!regExp.test(vTelNo)) {
            await $c.win.alert(MSG_LO_ERR_016);
            return;
        };
    }
    return true;
}


// 사용자 정보 확인
scwin.f_checkUserInfo = async function () {
    debugger
    let validVal = await scwin.f_AuthReqFieldChk()
    if (validVal) {
        ds_user.set("userId", txt_userId.getValue());
        ds_user.set("userNm", txt_userNm.getValue());
        ds_user.set("userMpNo", txt_userMpNo.getValue());
        ds_user.set("chk", "3")
        ds_user.set("oldPasswd", txt_oldPasswd.getValue());
        // tr_retrieveUser.post();
        $c.sbm.execute(sbm_retrieveUser);
    }
}


// 인증번호 전송
scwin.f_smsSend = async function () {
    $c.sbm.execute(sbm_saveAuthNo);
}

// 인증번호 확인
scwin.f_checkAuth = function () {
    if (scwin.vAuthNoYn == "N") {
        $c.win.alert(MSG_LO_ERR_014);
        return false;
    }

    if (txt_autnNo.getValue() == "") {
        $c.win.alert(MSG_LO_ERR_015);
        return false;
    }

    ds_confirm.set("authNo", txt_autnNo.getValue());
    ds_confirm.set("rcvNo", txt_userMpNo.getValue());
    ds_confirm.set("rcvNo2", txt_userMpNo.getValue());

    // tr_retrieveAuthNo.post();
    $c.sbm.execute(sbm_retrieveAuthNo);
}

scwin.f_TimerCount = function () {
    if (scwin.second == 00) {
        scwin.minute = scwin.minute - 1;
        scwin.second = 59;
    } else {
        scwin.second = scwin.second - 1;
    }

    if ((scwin.minute < 0) && (scwin.end == 0)) {
        if (scwin.vAuthNoYn == "Y") {
            $c.win.alert("인증시간이 지났습니다.");
        }
        scwin.vAuthNoYn = "N";
        scwin.minute = 5;
        scwin.second = 00;
        return;
    }

    txt_min.setValue(0 + scwin.minute.toString());
    if (scwin.second < 10) {
        txt_secs.setValue(0 + scwin.second.toString());
    } else {
        txt_secs.setValue(scwin.second);
    }

    setTimeout(function () {
        scwin.f_TimerCount();
    }, 1000);
}


// to-do
//숫자 입력 체크 
scwin.f_onlyNum = function (e) {
    var key = e.keyCode;

    if (!(key == 8 || key == 9 || key == 13
        || key == 46 || key == 144
        || (key >= 48 && key <= 57) || key == 110 || key == 190)
    ) {
        $c.win.alert('숫자만 입력 가능합니다');
        e.returnValue = false;
    }
}



//-------------------------------------------------------------------
//  G A U C E   C O M P O N E N T' S   E V E N T S  ->  TR 이벤트
//-------------------------------------------------------------------
scwin.sbm_saveEmp_submit = function (e) {
    oGDS_result_list.set("userId", txt_userId.getValue())
    oGDS_result_list.set("userNm", txt_userNm.getValue())
    oGDS_result_list.set("newPasswd", txt_newPasswd.getValue())
    oGDS_result_list.set("oldPasswd", txt_oldPasswd.getValue())
    oGDS_result_list.set("userMpNo", txt_userMpNo.getValue())
};

// CUD TR
scwin.sbm_saveEmp_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다

    // scwin.jsLogin(); // 해당함수에서 에러가 발생중 null값이 나오고있음
    scwin.vAuthNoYn = "N";
    scwin.minute = 0;
    scwin.second = 00;
    txt_oldPasswd.setValue("");
    txt_autnNo.setValue("");
    txt_userMpNo.setValue("");
    txt_newPasswd.setValue("");
    txt_confirmPasswd.setValue("");
    txt_secs.setValue("00");
    txt_min.setValue("00");
};


// 사용자 확인 TR
scwin.sbm_retrieveUser_submitdone = async function (e) {
    let vExistYn = ds_userResult.getCellData(0, "useYn");
    if (vExistYn == "1") {
        await scwin.f_smsSend();
        scwin.minute = 5;
        scwin.second = 00;
        scwin.f_TimerCount();
    }
};


scwin.sbm_saveAuthNo_submit = function (e) {
    ds_condition.set("userId", txt_userId.getValue())
    ds_condition.set("userNm", txt_userNm.getValue())
    ds_condition.set("userMpNo", txt_userMpNo.getValue())
    ds_condition.set("rcvNo", txt_userMpNo.getValue())

    // ds_condition.setCellData(0, "userId", txt_userId.getValue())
    // ds_condition.setCellData(0, "userNm", txt_userNm.getValue())
    // ds_condition.setCellData(0, "userMpNo", txt_userMpNo.getValue())
    // ds_condition.setCellData(0, "rcvNo", txt_userMpNo.getValue())
};


// 인증번호전송 TR
scwin.sbm_saveAuthNo_submitdone = function (e) {
    scwin.vAuthNoYn = "Y";
};


// 인증확인 TR
scwin.sbm_retrieveAuthNo_submitdone = function (e) {
    if (ds_result.getCellData(0, "authNo") != "") { // ds_result.CountRow > 0
        scwin.f_Update();
    } else {
        $c.win.alert("유효하지 않은 인증번호입니다.");
        return;
    }
};
